// Crisis keyword detection — runs BEFORE any AI agent
const message = $input.first().json.body.message || '';
const userId = $input.first().json.body.userId || 'anonymous';
const channel = $input.first().json.body.channel || 'web';

const CRISIS_KEYWORDS = [
  'suicide', 'kill myself', 'end my life', 'want to die',
  'cant go on', "can't go on", 'no point living', 'self harm',
  'hurt myself', 'overdose', 'not worth living'
];

const isCrisis = CRISIS_KEYWORDS.some(kw =>
  message.toLowerCase().includes(kw)
);

return [{
  json: {
    userId,
    message,
    channel,
    isCrisis,
    timestamp: new Date().toISOString()
  }
}];

// Parse all agent responses and bundle into one clean object
const items = $input.all();

// Get the risk agent response
const riskRaw = items[0]?.json?.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
let riskData = {};
try {
  const cleaned = riskRaw.replace(/```json|```/g, '').trim();
  riskData = JSON.parse(cleaned);
} catch (e) {
  riskData = { riskLevel: 'moderate', riskTitle: 'Some Signs of Distress', riskIcon: '🌤️', personalMessage: 'Your responses show some signs worth paying attention to.', keyInsight: '' };
}

// Get the care navigator response
const stepsRaw = items[1]?.json?.candidates?.[0]?.content?.parts?.[0]?.text || '[]';
let steps = [];
try {
  const cleaned = stepsRaw.replace(/```json|```/g, '').trim();
  steps = JSON.parse(cleaned);
} catch (e) {
  steps = ['Speak with your GP this week', 'Try the breathing exercise in our Resources', 'Check in again in 7 days'];
}

return [{
  json: {
    riskLevel: riskData.riskLevel || 'moderate',
    riskTitle: riskData.riskTitle || 'Check In With Someone',
    riskIcon: riskData.riskIcon || '🌤️',
    personalMessage: riskData.personalMessage || '',
    keyInsight: riskData.keyInsight || '',
    nextSteps: steps,
    timestamp: new Date().toISOString(),
    screeningComplete: true
  }
}];

// Store anonymised screening result
const result = $input.first().json;
const userId = $('crisis-check').first().json.userId;

// This would write to your database (Supabase / Airtable / Postgres)
// For now logs the anonymised record
console.log('Screening stored:', {
  anonymousId: userId,
  riskLevel: result.riskLevel,
  timestamp: result.timestamp
  // Never store message content — privacy first
});

return [{ json: { ...result, stored: true } }];

// Fetch patients due for follow-up from your DB
// In production: query Supabase/Airtable for users where
// lastScreening was 7, 30, or 90 days ago

// Mock data for demo:
return [
  { json: { userId: 'anon-001', daysSince: 7, lastRisk: 'moderate', channel: 'whatsapp' } },
  { json: { userId: 'anon-002', daysSince: 7, lastRisk: 'high', channel: 'sms' } }
];
